<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu — Desktop</title>
<style>
  :root{
    --orange:#e95420;
    --win-bg:#2f2f32;
  }
  *{margin:0;padding:0;box-sizing:border-box;}
  html,body{height:100%;}
  body{
    font-family:"Ubuntu","Segoe UI","Helvetica Neue",Arial,sans-serif;
    overflow:hidden;
    background:#160a19;
    color:#f0f0f0;
  }

  /* ============ desktop / wallpaper ============ */
  #desktop{
    position:fixed;
    inset:0;
    overflow:hidden;
    background:
      radial-gradient(900px 620px at 82% 108%, rgba(233,84,32,.55), rgba(233,84,32,0) 62%),
      radial-gradient(820px 620px at 8% -12%, rgba(119,33,111,.85), rgba(119,33,111,0) 60%),
      linear-gradient(158deg, #43124a 0%, #2c001e 46%, #160a19 100%);
  }
  #desktop::before{
    content:"";
    position:absolute;
    right:-12%; top:-25%;
    width:62%; height:150%;
    transform:skewX(-14deg);
    background:linear-gradient(115deg, rgba(255,255,255,.07), rgba(255,255,255,0) 55%);
    pointer-events:none;
  }
  #desktop::after{
    content:"";
    position:absolute;
    left:-180px; bottom:-220px;
    width:520px; height:520px;
    border-radius:50%;
    background:radial-gradient(circle at 35% 35%, rgba(255,255,255,.05), rgba(255,255,255,0) 65%);
    pointer-events:none;
  }

  /* ============ top taskbar ============ */
  #taskbar{
    position:absolute;
    top:0; left:0; right:0;
    height:36px;
    z-index:100000;
    display:flex;
    align-items:center;
    gap:6px;
    padding:0 10px;
    background:rgba(13,13,15,.9);
    border-bottom:1px solid rgba(255,255,255,.08);
    backdrop-filter:blur(10px);
  }
  .launcher{
    display:inline-flex;
    align-items:center;
    gap:7px;
    height:26px;
    padding:0 12px;
    border:none;
    border-radius:6px;
    background:transparent;
    color:#ececec;
    font:inherit;
    font-size:13px;
    cursor:pointer;
    position:relative;
  }
  .launcher:hover{background:rgba(255,255,255,.12);}
  .launcher:active{background:rgba(255,255,255,.18);}
  .launcher-ico{font-size:14px;}
  .launcher.running::after{
    content:"";
    position:absolute;
    bottom:1px; left:50%;
    transform:translateX(-50%);
    width:5px; height:5px;
    border-radius:50%;
    background:var(--orange);
  }
  #clock{
    position:absolute;
    left:50%; top:50%;
    transform:translate(-50%,-50%);
    font-size:13px;
    color:#f2f2f2;
    white-space:nowrap;
    pointer-events:none;
  }

  /* ============ windows ============ */
  .window{
    position:absolute;
    display:none;
    flex-direction:column;
    min-width:360px;
    min-height:240px;
    background:var(--win-bg);
    border-radius:10px;
    overflow:hidden;
    box-shadow:0 24px 60px rgba(0,0,0,.55), 0 0 0 1px rgba(255,255,255,.09);
  }
  .window.open{display:flex;}
  #files-window{left:80px; top:64px; width:640px; height:430px;}
  #notepad-window{left:230px; top:110px; width:660px; height:460px;}
  .win-titlebar{
    flex:0 0 auto;
    display:flex;
    align-items:center;
    gap:9px;
    height:38px;
    padding:0 8px 0 12px;
    background:linear-gradient(#3d3d40, #333336);
    border-bottom:1px solid rgba(0,0,0,.35);
    cursor:grab;
    user-select:none;
  }
  .win-titlebar:active{cursor:grabbing;}
  .win-ico{font-size:15px;}
  .win-title{flex:1; font-size:13.5px; font-weight:600; letter-spacing:.2px;}
  .win-close{
    width:20px; height:20px;
    border:none;
    border-radius:50%;
    background:#5b5b60;
    color:#fff;
    font-size:12px;
    line-height:1;
    cursor:pointer;
    display:inline-flex;
    align-items:center;
    justify-content:center;
    transition:background .15s;
  }
  .win-close:hover{background:var(--orange);}

  /* ============ files app ============ */
  .files-toolbar{
    flex:0 0 auto;
    display:flex;
    align-items:center;
    gap:8px;
    padding:8px 10px;
    background:#38383b;
    border-bottom:1px solid rgba(0,0,0,.3);
  }
  #files-up{
    width:32px; height:28px;
    border:1px solid rgba(255,255,255,.12);
    border-radius:6px;
    background:#454549;
    color:#fff;
    font-size:14px;
    cursor:pointer;
  }
  #files-up:hover{background:#54545a;}
  #files-path{
    flex:1;
    padding:6px 12px;
    background:#232325;
    border:1px solid rgba(255,255,255,.1);
    border-radius:6px;
    font-family:"Ubuntu Mono",Consolas,Menlo,monospace;
    font-size:13px;
    color:#ffcfba;
    overflow:hidden;
    text-overflow:ellipsis;
    white-space:nowrap;
  }
  #files-list{
    flex:1;
    overflow-y:auto;
    padding:14px;
    display:grid;
    grid-template-columns:repeat(auto-fill, minmax(96px, 1fr));
    gap:4px;
    align-content:start;
  }
  .fs-item{
    display:flex;
    flex-direction:column;
    align-items:center;
    gap:7px;
    padding:12px 6px 10px;
    border-radius:8px;
    font-size:12.5px;
    text-align:center;
    color:#eee;
    user-select:none;
    cursor:default;
    word-break:break-word;
    border:1px solid transparent;
  }
  .fs-item::before{font-size:34px; line-height:1; filter:drop-shadow(0 2px 2px rgba(0,0,0,.35));}
  .fs-item.folder::before{content:"📁";}
  .fs-item.file::before{content:"📄";}
  .fs-item.file[data-kind="image"]::before{content:"🖼️";}
  .fs-item.file[data-kind="audio"]::before{content:"🎵";}
  .fs-item.file[data-kind="text"]::before{content:"📝";}
  .fs-item.file[data-kind="archive"]::before{content:"📦";}
  .fs-item.file[data-kind="code"]::before{content:"📜";}
  .fs-item:hover{background:rgba(255,255,255,.07);}
  .fs-item.selected{
    background:rgba(233,84,32,.32);
    border-color:rgba(233,84,32,.8);
  }
  .files-status{
    flex:0 0 auto;
    padding:5px 12px;
    font-size:12px;
    color:#b9b9bd;
    background:#38383b;
    border-top:1px solid rgba(0,0,0,.3);
  }

  /* ============ notepad app ============ */
  #tabstrip{
    flex:0 0 auto;
    display:flex;
    align-items:flex-end;
    gap:5px;
    padding:6px 8px 0;
    background:#232325;
    border-bottom:1px solid rgba(0,0,0,.4);
    overflow-x:auto;
    overflow-y:hidden;
  }
  #tabs{display:flex; align-items:flex-end; gap:5px;}
  .tab{
    display:inline-flex;
    align-items:center;
    gap:8px;
    max-width:180px;
    min-width:64px;
    padding:7px 9px;
    background:#3a3a3e;
    border-radius:7px 7px 0 0;
    font-size:12.5px;
    color:#cfcfd2;
    cursor:pointer;
    user-select:none;
    border:1px solid rgba(255,255,255,.06);
    border-bottom:none;
  }
  .tab:hover{background:#45454a;}
  .tab.active{
    background:#1e1e20;
    color:#fff;
    box-shadow:inset 0 2px 0 var(--orange);
  }
  .tab-label{flex:1; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;}
  .tab-close{
    flex:0 0 auto;
    width:16px; height:16px;
    border-radius:50%;
    display:inline-flex;
    align-items:center;
    justify-content:center;
    font-size:11px;
    color:#a9a9ad;
  }
  .tab-close:hover{background:var(--orange); color:#fff;}
  #new-tab{
    flex:0 0 auto;
    width:26px; height:26px;
    margin-bottom:4px;
    border:none;
    border-radius:6px;
    background:#3a3a3e;
    color:#fff;
    font-size:16px;
    line-height:1;
    cursor:pointer;
  }
  #new-tab:hover{background:var(--orange);}
  #editor{
    flex:1;
    resize:none;
    border:none;
    outline:none;
    background:#1e1e20;
    color:#f3f3f3;
    padding:12px 14px;
    font-family:"Ubuntu Mono","Cascadia Code",Consolas,Menlo,monospace;
    font-size:14px;
    line-height:1.55;
  }
  #notepad-status{
    flex:0 0 auto;
    padding:4px 12px;
    font-size:12px;
    color:#a5a5a9;
    background:#232325;
    border-top:1px solid rgba(0,0,0,.4);
    text-align:right;
  }

  /* ============ toast ============ */
  #toast{
    position:absolute;
    left:50%; bottom:28px;
    transform:translate(-50%, 12px);
    background:rgba(18,18,20,.96);
    border:1px solid rgba(255,255,255,.12);
    color:#fff;
    padding:9px 16px;
    border-radius:8px;
    font-size:13px;
    opacity:0;
    pointer-events:none;
    transition:opacity .25s, transform .25s;
    z-index:100001;
    max-width:70%;
    text-align:center;
  }
  #toast.show{opacity:1; transform:translate(-50%, 0);}

  /* ============ scrollbars ============ */
  ::-webkit-scrollbar{width:10px; height:8px;}
  ::-webkit-scrollbar-thumb{background:rgba(255,255,255,.18); border-radius:5px;}
  ::-webkit-scrollbar-thumb:hover{background:rgba(255,255,255,.3);}
  ::-webkit-scrollbar-track{background:transparent;}
</style>
</head>
<body>
<div id="desktop">

  <header id="taskbar">
    <button id="open-files" class="launcher" type="button"><span class="launcher-ico">📁</span>Files</button>
    <button id="open-notepad" class="launcher" type="button"><span class="launcher-ico">📝</span>Text Editor</button>
    <div id="clock"></div>
  </header>

  <section id="files-window" class="window" aria-label="Files">
    <div class="win-titlebar">
      <span class="win-ico">📁</span>
      <span class="win-title">Files</span>
      <button class="win-close" type="button" title="Close">✕</button>
    </div>
    <div class="files-toolbar">
      <button id="files-up" type="button" title="Go up">↑</button>
      <div id="files-path">/</div>
    </div>
    <div id="files-list"></div>
    <div class="files-status" id="files-status"></div>
  </section>

  <section id="notepad-window" class="window" aria-label="Text Editor">
    <div class="win-titlebar">
      <span class="win-ico">📝</span>
      <span class="win-title">Text Editor</span>
      <button class="win-close" type="button" title="Close">✕</button>
    </div>
    <div id="tabstrip">
      <div id="tabs"></div>
      <button id="new-tab" type="button" title="New tab">+</button>
    </div>
    <textarea id="editor" spellcheck="false" placeholder="Type here…"></textarea>
    <div id="notepad-status">Ln 1, Col 1 — 0 characters</div>
  </section>

  <div id="toast"></div>
</div>

<script>
(function () {
  'use strict';

  /* ================= static fake filesystem ================= */
  function dir(children) { return { type: 'dir', children: children || {} }; }
  function file(content) { return { type: 'file', content: content }; }

  var FS = dir({
    bin: dir({
      bash: file(), cat: file(), cp: file(), echo: file(), grep: file(),
      ls: file(), mkdir: file(), mv: file(), rm: file(), sudo: file()
    }),
    boot: dir({
      'initrd.img': file(),
      'vmlinuz-6.8.0-generic': file(),
      grub: dir({
        'grub.cfg': file('# GRUB configuration\nset default=0\nset timeout=5\nset gfxmode=auto\n')
      })
    }),
    etc: dir({
      fstab: file('UUID=3f2a-91bc  /  ext4  errors=remount-ro  0  1\n'),
      hostname: file('ubuntu-desktop\n'),
      hosts: file('127.0.0.1\tlocalhost\n127.0.1.1\tubuntu-desktop\n'),
      'os-release': file('NAME="Ubuntu"\nVERSION="24.04 LTS (Noble Numbat)"\nID=ubuntu\nPRETTY_NAME="Ubuntu 24.04 LTS"\n'),
      passwd: file('root:x:0:0:root:/root:/bin/bash\nuser:x:1000:1000:user:/home/user:/bin/bash\n'),
      network: dir({
        interfaces: file('auto lo\niface lo inet loopback\n')
      })
    }),
    home: dir({
      user: dir({
        Documents: dir({
          'notes.txt': file('Shopping list\n--------------\n- coffee\n- tea\n- batteries\n- light bulbs\n'),
          'todo.txt': file('[x] finish the report\n[ ] water the plants\n[ ] call Sam back\n[ ] renew the domain\n'),
          'report.odt': file(),
          work: dir({
            'project-plan.md': file('# Project Plan\n\n1. Research\n2. Design\n3. Implementation\n4. Ship it!\n')
          })
        }),
        Downloads: dir({
          'archive.tar.gz': file(),
          'ubuntu-24.04-desktop.iso': file(),
          'wallpaper.png': file()
        }),
        Pictures: dir({
          'screenshot.png': file(),
          'vacation.jpg': file(),
          Cats: dir({
            'mittens.png': file(),
            'whiskers.jpg': file()
          })
        }),
        Music: dir({
          'lofi-beats.mp3': file(),
          'ocean-sounds.flac': file()
        }),
        '.bashrc': file('# ~/.bashrc\nalias ll="ls -alF"\nalias ..="cd .."\nexport EDITOR=nano\n'),
        '.profile': file('# ~/.profile\nexport PATH="$HOME/bin:$PATH"\n'),
        'welcome.txt': file('Welcome to your Ubuntu desktop!\n\nTips:\n- Double-click a folder to open it.\n- Double-click a text file to edit it in the Text Editor.\n- Use the Up button to go back.\n')
      })
    }),
    usr: dir({
      bin: dir({ gcc: file(), git: file(), python3: file(), vim: file() }),
      lib: dir({ 'libc.so.6': file(), 'libm.so.6': file() }),
      share: dir({
        doc: dir({ README: file('System-wide documentation lives here.\n') }),
        fonts: dir({ 'Ubuntu-Regular.ttf': file(), 'UbuntuMono-Regular.ttf': file() })
      })
    }),
    var: dir({
      cache: dir({ 'apt-lists.cache': file() }),
      log: dir({
        'auth.log': file('May  3 10:02:44 ubuntu sudo: user : TTY=pts/0 ; COMMAND=/usr/bin/apt update\n'),
        dmesg: file('[    0.000000] Linux version 6.8.0-31-generic (x86_64)\n'),
        syslog: file('May  3 10:01:12 ubuntu systemd[1]: Started Daily apt download activities.\n')
      }),
      tmp: dir({})
    })
  });

  /* ================= element refs ================= */
  var filesWin = document.getElementById('files-window');
  var notepadWin = document.getElementById('notepad-window');
  var filesList = document.getElementById('files-list');
  var filesPath = document.getElementById('files-path');
  var filesStatus = document.getElementById('files-status');
  var filesUp = document.getElementById('files-up');
  var tabsEl = document.getElementById('tabs');
  var editor = document.getElementById('editor');
  var notepadStatus = document.getElementById('notepad-status');
  var toast = document.getElementById('toast');
  var clock = document.getElementById('clock');

  /* ================= window manager ================= */
  var zTop = 10;
  function bringToFront(win) { win.style.zIndex = ++zTop; }
  function showWindow(win) { win.classList.add('open'); bringToFront(win); syncLaunchers(); }
  function hideWindow(win) { win.classList.remove('open'); syncLaunchers(); }
  function syncLaunchers() {
    document.getElementById('open-files').classList.toggle('running', filesWin.classList.contains('open'));
    document.getElementById('open-notepad').classList.toggle('running', notepadWin.classList.contains('open'));
  }

  document.getElementById('open-files').addEventListener('click', function () { showWindow(filesWin); });
  document.getElementById('open-notepad').addEventListener('click', function () { showWindow(notepadWin); });

  Array.prototype.forEach.call(document.querySelectorAll('.window'), function (win) {
    win.addEventListener('mousedown', function () { bringToFront(win); });
    win.querySelector('.win-close').addEventListener('click', function () { hideWindow(win); });
    var bar = win.querySelector('.win-titlebar');
    bar.addEventListener('mousedown', function (e) {
      if (e.target.closest('.win-close')) return;
      e.preventDefault();
      var rect = win.getBoundingClientRect();
      var dx = e.clientX - rect.left;
      var dy = e.clientY - rect.top;
      function onMove(ev) {
        var x = Math.min(Math.max(ev.clientX - dx, -rect.width + 80), window.innerWidth - 60);
        var y = Math.min(Math.max(ev.clientY - dy, 36), window.innerHeight - 30);
        win.style.left = x + 'px';
        win.style.top = y + 'px';
      }
      function onUp() {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
      }
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    });
  });

  /* ================= Files app ================= */
  var currentPath = '/';

  function resolveNode(path) {
    var node = FS;
    if (path === '/') return node;
    var parts = path.split('/').filter(Boolean);
    for (var i = 0; i < parts.length; i++) {
      if (!node.children || !node.children[parts[i]]) return null;
      node = node.children[parts[i]];
    }
    return node;
  }
  function parentPath(path) {
    if (path === '/') return '/';
    var parts = path.split('/').filter(Boolean);
    parts.pop();
    return parts.length ? '/' + parts.join('/') : '/';
  }
  function joinPath(base, name) { return base === '/' ? '/' + name : base + '/' + name; }

  function kindOf(name) {
    var m = /\.([a-z0-9]+)$/i.exec(name);
    var ext = m ? m[1].toLowerCase() : '';
    if (['png','jpg','jpeg','gif','webp','svg'].indexOf(ext) >= 0) return 'image';
    if (['mp3','ogg','flac','wav'].indexOf(ext) >= 0) return 'audio';
    if (['txt','md','log','conf','cfg'].indexOf(ext) >= 0) return 'text';
    if (['zip','gz','tar','xz','iso','deb'].indexOf(ext) >= 0) return 'archive';
    if (['sh','py','c','h','js','json','html','css'].indexOf(ext) >= 0) return 'code';
    return 'plain';
  }

  function renderFiles() {
    filesPath.textContent = currentPath;
    filesList.innerHTML = '';
    var node = resolveNode(currentPath) || FS;
    var names = Object.keys(node.children);
    names.sort(function (a, b) {
      var ad = node.children[a].type === 'dir';
      var bd = node.children[b].type === 'dir';
      if (ad !== bd) return ad ? -1 : 1;
      return a.localeCompare(b, undefined, { sensitivity: 'base' });
    });
    names.forEach(function (name) {
      var meta = node.children[name];
      var el = document.createElement('div');
      el.className = 'fs-item ' + (meta.type === 'dir' ? 'folder' : 'file');
      if (meta.type === 'file') el.setAttribute('data-kind', kindOf(name));
      el.textContent = name;
      el.title = name;
      el.addEventListener('click', function () {
        Array.prototype.forEach.call(filesList.querySelectorAll('.fs-item.selected'), function (x) {
          x.classList.remove('selected');
        });
        el.classList.add('selected');
      });
      el.addEventListener('dblclick', function () {
        if (meta.type === 'dir') {
          navigate(joinPath(currentPath, name));
        } else if (typeof meta.content === 'string') {
          openInNotepad(name, meta.content);
        } else {
          showToast('Cannot open “' + name + '”: no application available for this file type.');
        }
      });
      filesList.appendChild(el);
    });
    filesStatus.textContent = names.length + (names.length === 1 ? ' item' : ' items') + ' — ' + currentPath;
  }

  function navigate(path) {
    if (!resolveNode(path)) return;
    currentPath = path;
    renderFiles();
  }

  filesUp.addEventListener('click', function () { navigate(parentPath(currentPath)); });

  /* ================= Notepad app ================= */
  var LS_KEY = 'ubuntu-desktop.notepad.v1';
  var state;

  function defaultState() {
    return { counter: 1, activeId: 1, tabs: [{ id: 1, base: 'Untitled 1', title: 'Untitled 1', content: '' }] };
  }
  function saveState() {
    try { localStorage.setItem(LS_KEY, JSON.stringify(state)); } catch (e) {}
  }
  function loadState() {
    try {
      var raw = localStorage.getItem(LS_KEY);
      if (raw) {
        var s = JSON.parse(raw);
        if (s && Array.isArray(s.tabs) && s.tabs.length) {
          state = s;
          var maxId = s.counter || 0;
          s.tabs.forEach(function (t) { if (t.id > maxId) maxId = t.id; });
          state.counter = maxId;
          if (!state.tabs.some(function (t) { return t.id === state.activeId; })) {
            state.activeId = state.tabs[0].id;
          }
          return;
        }
      }
    } catch (e) {}
    state = defaultState();
    saveState();
  }
  function activeTab() {
    var t = state.tabs.find(function (t) { return t.id === state.activeId; });
    return t || state.tabs[0];
  }

  function renderTabs() {
    tabsEl.innerHTML = '';
    state.tabs.forEach(function (tab) {
      var el = document.createElement('div');
      el.className = 'tab' + (tab.id === state.activeId ? ' active' : '');
      var label = document.createElement('span');
      label.className = 'tab-label';
      label.textContent = tab.title;
      var x = document.createElement('span');
      x.className = 'tab-close';
      x.textContent = '×';
      x.title = 'Close tab';
      x.addEventListener('click', function (ev) { ev.stopPropagation(); closeTab(tab.id); });
      el.appendChild(label);
      el.appendChild(x);
      el.addEventListener('click', function () { activateTab(tab.id); });
      tabsEl.appendChild(el);
    });
  }

  function activateTab(id) {
    state.activeId = id;
    var tab = activeTab();
    editor.value = tab.content;
    renderTabs();
    updateStatus();
    saveState();
  }

  function createTab(base, content, locked) {
    var id = ++state.counter;
    var name = base || ('Untitled ' + id);
    state.tabs.push({ id: id, base: name, title: name, content: content || '', locked: !!locked });
    activateTab(id);
  }

  function closeTab(id) {
    var i = state.tabs.findIndex(function (t) { return t.id === id; });
    if (i < 0) return;
    state.tabs.splice(i, 1);
    if (!state.tabs.length) { createTab(); return; }
    if (state.activeId === id) {
      activateTab(state.tabs[Math.min(i, state.tabs.length - 1)].id);
    } else {
      renderTabs();
      saveState();
    }
  }

  document.getElementById('new-tab').addEventListener('click', function () { createTab(); });

  editor.addEventListener('input', function () {
    var tab = activeTab();
    tab.content = editor.value;
    if (!tab.locked) {
      var first = '';
      var lines = editor.value.split('\n');
      for (var i = 0; i < lines.length; i++) {
        if (lines[i].trim().length) { first = lines[i].trim(); break; }
      }
      tab.title = first.slice(0, 20) || tab.base;
      var label = tabsEl.querySelector('.tab.active .tab-label');
      if (label) label.textContent = tab.title;
    }
    saveState();
    updateStatus();
  });
  ['keyup', 'click', 'select'].forEach(function (ev) {
    editor.addEventListener(ev, updateStatus);
  });

  function updateStatus() {
    var pos = editor.selectionStart || 0;
    var upto = editor.value.slice(0, pos);
    var line = upto.split('\n').length;
    var col = pos - upto.lastIndexOf('\n');
    var total = editor.value.length;
    notepadStatus.textContent = 'Ln ' + line + ', Col ' + col + ' — ' + total + (total === 1 ? ' character' : ' characters');
  }

  function openInNotepad(name, content) {
    var existing = state.tabs.find(function (t) { return t.locked && t.base === name; });
    if (existing) activateTab(existing.id);
    else createTab(name, content, true);
    showWindow(notepadWin);
  }

  window.addEventListener('beforeunload', function () {
    var tab = activeTab();
    if (tab) tab.content = editor.value;
    saveState();
  });

  /* ================= toast & clock ================= */
  var toastTimer = null;
  function showToast(msg) {
    toast.textContent = msg;
    toast.classList.add('show');
    clearTimeout(toastTimer);
    toastTimer = setTimeout(function () { toast.classList.remove('show'); }, 2400);
  }

  function tick() {
    var d = new Date();
    var date = d.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
    var time = d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
    clock.textContent = date + '   ' + time;
  }

  /* ================= init ================= */
  renderFiles();
  loadState();
  renderTabs();
  editor.value = activeTab().content;
  updateStatus();
  tick();
  setInterval(tick, 1000);
})();
